def select_action(obs: np.ndarray) -> int:
    ball_x = obs[49]
    ball_y = obs[54]
    paddle_y = obs[51]

    # Velocity estimation from ball position relative to screen
    if ball_y < 105:
        vert_vel = -3
    else:
        vert_vel = 3

    # Determine ball direction
    ball_coming = ball_x > 80  # ball on right half coming toward player

    if ball_coming:
        # Aggressive tracking with velocity-aware dead zone
        error = ball_y - (paddle_y + 10)
        dead_zone = max(4, abs(vert_vel) * 2)
        if error < -dead_zone:
            return 2
        elif error > dead_zone:
            return 3
        return 0
    else:
        # Defensive centering: move toward middle of screen
        target_y = 105  # screen vertical center
        error = target_y - (paddle_y + 10)
        dead_zone = 8
        if error < -dead_zone:
            return 2
        elif error > dead_zone:
            return 3
        return 0
